python3 - <<'EOF'
import re

doc = open('/home/harri/scsi-experimenter-software/ARCHITECTURE.md').read()
blocks = re.findall(r'```pioasm\n(.*?)```', doc, re.S)
T = 1e9/24e6  # ns per SM cycle @ 24 MHz
SYNC = 2*(1e9/120e6)  # input synchronizer age, ns

total_instr = 0
for b in blocks:
    name = re.search(r'\.program (\S+)', b).group(1)
    lines = [l.split(';')[0].strip() for l in b.splitlines()]
    lines = [l for l in lines if l and not l.startswith('.')]
    errs, prog = [], []
    for l in lines:
        m = re.match(r'(?:(\w+):\s*)?(\S.*?)\s+side\s+0b([01]+)(?:\s*\[(\d+)\])?$', l)
        if not m:
            # instruction without side annotation? (illegal with non-opt side_set)
            if re.match(r'(?:\w+:\s*)?\S', l): errs.append(f"NO SIDE ANNOTATION: {l!r}")
            continue
        instr, side, delay = m.group(2), int(m.group(3),2), int(m.group(4) or 0)
        if side > 7: errs.append(f"side {side} > 3 bits: {l!r}")
        if delay > 3: errs.append(f"delay [{delay}] > 2 bits (max [3] w/ .side_set 3): {l!r}")
        prog.append((instr, side, delay))
    n = len(prog); total_instr += n
    print(f"{name}: {n} instr, {'OK' if not errs else 'ERRORS'}")
    for e in errs: print("   !!", e)

    # timing simulation: track each side bit; measure low-pulse widths & sample points
    # identify strobe bits by which change from idle 0b111
    t = 0.0; fall = {}; events = []
    for instr, side, delay in prog:
        for bit in range(3):
            lv = (side>>bit)&1
            if lv==0 and bit not in fall: fall[bit]=t
            if lv==1 and bit in fall:
                events.append((f"bit{bit} low", fall.pop(bit), t-fall_w if False else t- events_dummy if False else t))
        # simpler: record rise
        if instr.startswith('in'):
            lows = {b: t-f for b,f in fall.items()}
            events.append(("SAMPLE", t, {f"bit{b}": v for b,v in lows.items()}))
        t += (1+delay)*T
    # second pass, cleaner:
    t=0.0; fall={}; pulses=[]; samples=[]
    for instr, side, delay in prog:
        for bit in range(3):
            lv=(side>>bit)&1
            if lv==0 and bit not in fall: fall[bit]=t
            elif lv==1 and bit in fall: pulses.append((bit, t-fall.pop(bit)))
        if instr.startswith('in'): samples.append({b: t-f for b,f in fall.items()})
        t += (1+delay)*T
    loop = t  # one pass length (wrap: strobes released before loop end in all progs)
    for bit,w in pulses: print(f"   strobe bit{bit}: low {w:.1f} ns")
    for s in samples:
        for b,dt in s.items(): print(f"   IN sample: {dt:.1f} ns after bit{b} fell -> data age {dt-SYNC:.1f} ns (sync -{SYNC:.1f})")
    print(f"   loop pass: {loop:.1f} ns ({t/T:.0f} cycles)")
print(f"TOTAL: {total_instr} / 32 instruction slots")
EOF

